mapper.select:
select id, order_no as orderNo, user_id as userId, status, total_amount as totalAmount, total_quantity as totalQuantity, created_at as createdAt, updated_at as updatedAt from orders where user_id = #{userId}
and status = #{status}
order by total_amount asc, id asc
order by total_amount desc, id desc
order by created_at asc, id asc
order by created_at desc, id desc
limit #{offset}, #{size}

select count(*)
from orders
where user_id = #{userId}

    and status = #{status}
